const allConfigs = queries.fetchAllConfigs?.data ?? [];
if (!Array.isArray(allConfigs) || allConfigs.length === 0) {
  await actions.showAlert("No configs to copy")
  // utils.showNotification({
  //   title: "No configs to copy",
  //   notificationType: "error"
  // })
  return "No configs to copy";
}
const targetService = components.selectTargetServiceCopyConfigModal.value;
//configListInput.setValue([]);
await actions.setPageVariable("configListInput",[])
let tempConfigListInput = [];
for (const cfg of allConfigs) {
  const body = {
    config_param: {
      config_param_name: cfg.config_param_name,
      service_name: targetService,
      param_type: cfg.param_type,
      value_type: cfg.value_type,
      dimensions: cfg.dimensions,
      created_by: {
        name: globals.currentUser.firstName +" "+ globals.currentUser.lastName,
        email_id: globals.currentUser.email
      },
      metadata: {
        description: cfg.metadata?.description,
        config_type: cfg.metadata?.config_type
      }
    },
    pre_approval: {
      type: 1,
      pre_approval_link: "https://swiggy.atlassian.net/browse/CMR-111709"
    }
  };

  console.log("Calling addCopyConfig for:", cfg.config_param_name);
  tempConfigListInput.push(body);
}

//configListInput.setValue(tempConfigListInput);
await actions.setPageVariable("configListInput",tempConfigListInput)

//addConfigCopyIndex.setValue(0);
await actions.setPageVariable("addConfigCopyIndex",0)

for(let i = 0; i < tempConfigListInput.length; i++) {
  //addConfigCopyIndex.setValue(i);
  await actions.setPageVariable("addConfigCopyIndex",i)
  await queries.addConfigCopy.run();
}
